import '../../styles/Main.css';
import { useEffect, useState } from "react";

function App() {

  const [scaleMessage, setScaleMessage] = useState(null)
  const [lastScaleWeight, setLastWeight] = useState(null)
  const [diff, setDiff] = useState(null)

  const [forkMessage, setForkMessage] = useState(null)
  const [cutCount, setCutCount] = useState(null)

  useEffect(() => {
    let ws; 

    const connectWebSocket = () => {
      ws = new WebSocket("ws://dex.local:8765");

      ws.onopen = () => {
        console.log("Connected to sensor WebSocket");
      };

      ws.onmessage = (event) => {
        const data = JSON.parse(event.data);
        if (data.source === "scale") {
            setScaleMessage(data.message)
            setLastWeight(data.lastWeight)
            setDiff(data.diff)
        }
        else if (data.source === "fork") {
            setForkMessage(data.message)
            setCutCount(data.cutCount) 
        } 
        else{
          console.log("ERROR")
        }
      };

      ws.onerror = (err) => {
        console.error("WebSocket error:", err);
      };

      ws.onclose = () => {
        console.warn("WebSocket closed, retrying in 1 second...");
        setTimeout(connectWebSocket, 1000);
      };

    };

    connectWebSocket(); 

    return () => ws && ws.close();
  }, []);

  const startSensors = () => {
    console.log("Pressed ")
    //start all sensors to read from loadSensor.py 
    fetch("/start-sensors", { method: "POST" })
      .then(res => res.json())
      .then(data => console.log(data));
    };


  return (
    <div className="App">
      <header className="App-header">
        <button onClick={startSensors}>Start Sensors</button>
        <div style={{ marginTop: "30px" }}>
          <p>
            <strong style={{ color: "limegreen" }}>
              {scaleMessage || "Waiting"} <br/>
                Last weight: {lastScaleWeight} <br/>
                Diff: {diff}
            </strong>
            <br/>
            <strong style={{ color: "limegreen" }}>
              {forkMessage || "Waiting"} <br/>
              Cut count: {cutCount}
            </strong>
          </p>
        </div>
      </header>
    </div>
  );
}

export default App;
